const com_nav_info_save_badges_state$c = "هنگامی که این گزینه فعال باشد، وضعیت نشان‌های چت ذخیره می‌شود. این بدان معناست که اگر یک چت جدید ایجاد کنید، نشان‌ها در همان وضعیت چت قبلی باقی خواهند ماند. اگر این گزینه را غیرفعال کنید، نشان‌ها در هر بار ایجاد یک چت جدید به حالت پیش‌فرض بازنشانی می‌شوند.";
const com_nav_info_save_draft$i = "وقتی فعال باشد، متن و پیوست‌هایی که در فرم چت وارد می‌کنید به‌طور خودکار به‌صورت محلی به‌عنوان پیش‌نویس ذخیره می‌شوند. این پیش‌نویس‌ها در دسترس خواهند بود حتی اگر صفحه را دوباره بارگیری کنید یا به مکالمه دیگری بروید. پیش نویس ها به صورت محلی در دستگاه شما ذخیره می شوند و پس از ارسال پیام حذف می شوند.";
const com_nav_info_show_thinking$g = "وقتی فعال باشد، چت به طور پیش‌فرض فهرست‌های بازشوی تفکر را نشان می‌دهد و به شما امکان می‌دهد استدلال هوش مصنوعی را در زمان واقعی مشاهده کنید. وقتی غیرفعال باشد، منوهای کشویی تفکر به طور پیش‌فرض بسته می‌مانند تا رابطی تمیزتر و کارآمدتر داشته باشند";
const com_nav_info_user_name_display$h = 'وقتی فعال باشد، نام کاربری فرستنده بالای هر پیامی که ارسال می کنید نشان داده می شود. هنگامی که غیرفعال است، فقط "شما" را در بالای پیام های خود خواهید دید.';
